// src/components/AddTask.jsx
import React, { useState, useEffect } from "react";
import {
  addTask,
  addUser,
  CHORE_POINTS,
  getUsers
} from "../firebase/firebaseService";

export default function AddTask({ onUpdate, goToTasks }) {
  const [title, setTitle] = useState("");
  const [customTitle, setCustomTitle] = useState("");
  const [assignedTo, setAssignedTo] = useState("");
  const [customPoints, setCustomPoints] = useState("");
  const [newUser, setNewUser] = useState("");
  const [users, setUsers] = useState([]);
  const [toast, setToast] = useState(null);
  const [dueDate, setDueDate] = useState("");

  useEffect(() => {
    getUsers().then(setUsers);
  }, []);

  const choreOptions = Object.keys(CHORE_POINTS);

  const showToast = (msg, type = "success") => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  };

  const handleAddTask = async () => {
    const finalTitle = title === "Custom" ? customTitle.trim() : title;

    if (!finalTitle) return showToast("Select a chore", "error");
    if (!assignedTo.trim()) return showToast("Enter roommate name", "error");

    let user =
      users.find(
        (u) => u.name.toLowerCase() === assignedTo.toLowerCase()
      ) || (await addUser(assignedTo.trim()));

    const pts =
      title === "Custom" && customPoints
        ? parseInt(customPoints)
        : CHORE_POINTS[title] || 10;

    await addTask({
      title: finalTitle,
      assignedTo: user.uid,
      assignedName: user.name,
      points: pts,
      dueDate: dueDate || null,
      status: "pending"
    });

    showToast("Task added successfully!");

    setTitle("");
    setCustomTitle("");
    setAssignedTo("");
    setCustomPoints("");
    setDueDate("");

    onUpdate();
    goToTasks?.(); // auto switch tab
  };

  const handleAddUser = async () => {
    if (!newUser.trim()) return;
    await addUser(newUser.trim());
    setNewUser("");
    onUpdate();
  };

  return (
    <div className="card">
      <h2 className="card-title">➕ Add Task</h2>

      {toast && <div className={`toast ${toast.type}`}>{toast.msg}</div>}

      {/* CHORE */}
      <div className="form-row">
        <label>Chore</label>
        <select value={title} onChange={(e) => setTitle(e.target.value)}>
          <option value="">Select</option>
          {choreOptions.map((c) => (
            <option key={c} value={c}>
              {c} ({CHORE_POINTS[c]} pts)
            </option>
          ))}
          <option value="Custom">Custom</option>
        </select>
      </div>

      {title === "Custom" && (
        <>
          <div className="form-row">
            <label>Name</label>
            <input
              value={customTitle}
              onChange={(e) => setCustomTitle(e.target.value)}
            />
          </div>

          <div className="form-row">
            <label>Points</label>
            <input
              type="number"
              value={customPoints}
              onChange={(e) => setCustomPoints(e.target.value)}
            />
          </div>
        </>
      )}

      {/* ASSIGN */}
      <div className="form-row">
        <label>Assign To</label>
        <input
          value={assignedTo}
          onChange={(e) => setAssignedTo(e.target.value)}
          list="users"
        />
        <datalist id="users">
          {users.map((u) => (
            <option key={u.uid} value={u.name} />
          ))}
        </datalist>
      </div>

      {/* DUE DATE */}
      <div className="form-row">
        <label>Due Date</label>
        <input
          type="date"
          value={dueDate}
          onChange={(e) => setDueDate(e.target.value)}
        />
      </div>

      <button className="btn btn-primary" onClick={handleAddTask}>
        Add Task
      </button>

      <hr className="divider" />

      <h3 className="section-label">Add Roommate</h3>
      <div className="form-row">
        <input
          value={newUser}
          onChange={(e) => setNewUser(e.target.value)}
          placeholder="Name"
        />
        <button className="btn btn-secondary" onClick={handleAddUser}>
          Add
        </button>
      </div>
    </div>
  );
}
